// Cloudflare Worker with SendGrid and Stripe Integration

const ALLOWED_ORIGINS = ['https://yourdomain.com', 'https://www.yourdomain.com'];

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Methods': 'GET, POST, OPTIONS',
  'Access-Control-Allow-Headers': 'Content-Type, Authorization',
  'Access-Control-Max-Age': '86400',
};

class APIError extends Error {
  constructor(message, status = 500, code = 'INTERNAL_ERROR') {
    super(message);
    this.status = status;
    this.code = code;
  }
}

async function handleSendEmail(request, env) {
  const body = await request.json();
  const { to, subject, text, html } = body;

  if (!to || !subject || (!text && !html)) {
    throw new APIError('Missing required fields: to, subject, and text or html', 400, 'INVALID_REQUEST');
  }

  const emailData = {
    personalizations: [
      {
        to: [{ email: to }],
        subject: subject,
      },
    ],
    from: {
      email: env.SENDGRID_FROM_EMAIL || 'noreply@yourdomain.com',
      name: env.SENDGRID_FROM_NAME || 'Your App',
    },
    content: [],
  };

  if (text) {
    emailData.content.push({
      type: 'text/plain',
      value: text,
    });
  }

  if (html) {
    emailData.content.push({
      type: 'text/html',
      value: html,
    });
  }

  const response = await fetch('https://api.sendgrid.com/v3/mail/send', {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${env.SENDGRID_API_KEY}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(emailData),
  });

  if (!response.ok) {
    const errorText = await response.text();
    let errorMessage = 'Failed to send email';
    try {
      const errorJson = JSON.parse(errorText);
      errorMessage = errorJson.errors?.[0]?.message || errorMessage;
    } catch (e) {
      errorMessage = errorText || errorMessage;
    }
    throw new APIError(errorMessage, response.status, 'SENDGRID_ERROR');
  }

  return {
    success: true,
    message: 'Email sent successfully',
    messageId: response.headers.get('X-Message-Id'),
  };
}

async function handleCreatePaymentIntent(request, env) {
  const body = await request.json();
  const { amount, currency = 'usd', description, metadata = {} } = body;

  if (!amount || amount <= 0) {
    throw new APIError('Invalid amount', 400, 'INVALID_AMOUNT');
  }

  const params = new URLSearchParams({
    amount: Math.round(amount),
    currency: currency.toLowerCase(),
  });

  if (description) {
    params.append('description', description);
  }

  Object.keys(metadata).forEach(key => {
    params.append(`metadata[${key}]`, metadata[key]);
  });

  const response = await fetch('https://api.stripe.com/v1/payment_intents', {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${env.STRIPE_SECRET_KEY}`,
      'Content-Type': 'application/x-www-form-urlencoded',
    },
    body: params.toString(),
  });

  const data = await response.json();

  if (!response.ok) {
    throw new APIError(
      data.error?.message || 'Failed to create payment intent',
      response.status,
      data.error?.code || 'STRIPE_ERROR'
    );
  }

  return {
    success: true,
    paymentIntent: {
      id: data.id,
      clientSecret: data.client_secret,
      amount: data.amount,
      currency: data.currency,
      status: data.status,
    },
  };
}

async function handleRetrievePayment(request, env, paymentIntentId) {
  if (!paymentIntentId) {
    throw new APIError('Payment intent ID is required', 400, 'INVALID_REQUEST');
  }

  const response = await fetch(`https://api.stripe.com/v1/payment_intents/${paymentIntentId}`, {
    method: 'GET',
    headers: {
      'Authorization': `Bearer ${env.STRIPE_SECRET_KEY}`,
    },
  });

  const data = await response.json();

  if (!response.ok) {
    throw new APIError(
      data.error?.message || 'Failed to retrieve payment',
      response.status,
      data.error?.code || 'STRIPE_ERROR'
    );
  }

  return {
    success: true,
    payment: {
      id: data.id,
      amount: data.amount,
      currency: data.currency,
      status: data.status,
      created: data.created,
      description: data.description,
      metadata: data.metadata,
    },
  };
}

async function handleCreateCustomer(request, env) {
  const body = await request.json();
  const { email, name, description, metadata = {} } = body;

  if (!email) {
    throw new APIError('Email is required', 400, 'INVALID_REQUEST');
  }

  const params = new URLSearchParams({ email });

  if (name) params.append('name', name);
  if (description) params.append('description', description);

  Object.keys(metadata).forEach(key => {
    params.append(`metadata[${key}]`, metadata[key]);
  });

  const response = await fetch('https://api.stripe.com/v1/customers', {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${env.STRIPE_SECRET_KEY}`,
      'Content-Type': 'application/x-www-form-urlencoded',
    },
    body: params.toString(),
  });

  const data = await response.json();

  if (!response.ok) {
    throw new APIError(
      data.error?.message || 'Failed to create customer',
      response.status,
      data.error?.code || 'STRIPE_ERROR'
    );
  }

  return {
    success: true,
    customer: {
      id: data.id,
      email: data.email,
      name: data.name,
      created: data.created,
    },
  };
}

async function handleWebhook(request, env) {
  const signature = request.headers.get('stripe-signature');
  
  if (!signature) {
    throw new APIError('Missing stripe-signature header', 400, 'INVALID_WEBHOOK');
  }

  const body = await request.text();

  try {
    const event = JSON.parse(body);
    
    console.log('Webhook received:', event.type);

    switch (event.type) {
      case 'payment_intent.succeeded':
        console.log('Payment succeeded:', event.data.object.id);
        break;
      case 'payment_intent.payment_failed':
        console.log('Payment failed:', event.data.object.id);
        break;
      case 'customer.created':
        console.log('Customer created:', event.data.object.id);
        break;
      default:
        console.log('Unhandled event type:', event.type);
    }

    return {
      success: true,
      received: true,
      eventType: event.type,
    };
  } catch (error) {
    throw new APIError('Invalid webhook payload', 400, 'INVALID_WEBHOOK');
  }
}

function validateApiKey(request, env) {
  const authHeader = request.headers.get('Authorization');
  
  if (!authHeader) {
    throw new APIError('Missing Authorization header', 401, 'UNAUTHORIZED');
  }

  const [type, token] = authHeader.split(' ');

  if (type !== 'Bearer' || !token) {
    throw new APIError('Invalid Authorization format', 401, 'UNAUTHORIZED');
  }

  if (token !== env.API_KEY) {
    throw new APIError('Invalid API key', 403, 'FORBIDDEN');
  }

  return true;
}

function validateOrigin(request) {
  const origin = request.headers.get('Origin');
  
  if (origin && !ALLOWED_ORIGINS.includes(origin)) {
    return false;
  }
  
  return true;
}

async function handleRequest(request, env) {
  const url = new URL(request.url);
  const path = url.pathname;

  if (request.method === 'OPTIONS') {
    return new Response(null, { headers: corsHeaders });
  }

  if (path === '/webhook/stripe') {
    return await handleWebhook(request, env);
  }

  validateApiKey(request, env);

  if (request.method === 'POST' && path === '/email/send') {
    return await handleSendEmail(request, env);
  }

  if (request.method === 'POST' && path === '/payment/create') {
    return await handleCreatePaymentIntent(request, env);
  }

  if (request.method === 'GET' && path.startsWith('/payment/')) {
    const paymentIntentId = path.split('/')[2];
    return await handleRetrievePayment(request, env, paymentIntentId);
  }

  if (request.method === 'POST' && path === '/customer/create') {
    return await handleCreateCustomer(request, env);
  }

  if (path === '/health') {
    return {
      success: true,
      status: 'healthy',
      timestamp: new Date().toISOString(),
    };
  }

  throw new APIError('Not found', 404, 'NOT_FOUND');
}

async function handleErrors(request, env) {
  try {
    const result = await handleRequest(request, env);
    
    return new Response(JSON.stringify(result), {
      status: 200,
      headers: {
        'Content-Type': 'application/json',
        ...corsHeaders,
      },
    });
  } catch (error) {
    console.error('Error:', error);

    const status = error.status || 500;
    const code = error.code || 'INTERNAL_ERROR';
    const message = error.message || 'Internal server error';

    return new Response(
      JSON.stringify({
        success: false,
        error: {
          code,
          message,
        },
      }),
      {
        status,
        headers: {
          'Content-Type': 'application/json',
          ...corsHeaders,
        },
      }
    );
  }
}

export default {
  async fetch(request, env, ctx) {
    if (!env.SENDGRID_API_KEY) {
      return new Response(
        JSON.stringify({
          success: false,
          error: {
            code: 'CONFIGURATION_ERROR',
            message: 'SENDGRID_API_KEY not configured',
          },
        }),
        {
          status: 500,
          headers: { 'Content-Type': 'application/json', ...corsHeaders },
        }
      );
    }

    if (!env.STRIPE_SECRET_KEY) {
      return new Response(
        JSON.stringify({
          success: false,
          error: {
            code: 'CONFIGURATION_ERROR',
            message: 'STRIPE_SECRET_KEY not configured',
          },
        }),
        {
          status: 500,
          headers: { 'Content-Type': 'application/json', ...corsHeaders },
        }
      );
    }

    if (!env.API_KEY) {
      return new Response(
        JSON.stringify({
          success: false,
          error: {
            code: 'CONFIGURATION_ERROR',
            message: 'API_KEY not configured',
          },
        }),
        {
          status: 500,
          headers: { 'Content-Type': 'application/json', ...corsHeaders },
        }
      );
    }

    return handleErrors(request, env);
  },
};